# ═══════════════════════════════════════════════════════════════
# Period Dimension Subset Rebuild
# ═══════════════════════════════════════════════════════════════
# Dimension: GBL Period
# Purpose : Destroys and recreates all selected public subsets
# Input   : pCurrentPeriod — the month to use as reference
# Output  : Rebuild subsets in the target dimension
# ═══════════════════════════════════════════════════════════════

# vCount = total number of elements in the dimension
vCount = DIMSIZ(pDimension);


# ─────────────────────────────────────────────
# Validate & Resolve Current Period
# Reads pCurrentPeriod parameter (e.g. '2027-04')
# Extracts: FY name, prior FY/period
# Also computes YTD/YTG/LTD consolidation names
# ─────────────────────────────────────────────
# ── Validate Current Period ──
# Check: parameter must not be empty
IF(pCurrentPeriod @= '');
  ItemReject('pCurrentPeriod is required — set a period e.g. 2027-05');
  ProcessQuit;
ENDIF;
IF(DIMIX(pDimension, pCurrentPeriod) = 0);
  ItemReject('Period not found in dimension: ' | pCurrentPeriod);
  ProcessQuit;
ENDIF;

# Read current period attribute values
# ── Read attribute values from current period element ──
# sCurrentFY = Fin Year attribute of current period (e.g. 'FY2027')
sCurrentFY = ATTRS(pDimension, pCurrentPeriod, 'Fin Year');
# sPriorPeriod = element name of the month before current
sPriorPeriod = ATTRS(pDimension, pCurrentPeriod, 'Previous Period');
# sYTD = name of the YTD consolidation for current period (e.g. 'YTD FY2027 P01')
sYTD = ATTRS(pDimension, pCurrentPeriod, 'YTD');
# sYTG = name of the YTG consolidation for current period
sYTG = ATTRS(pDimension, pCurrentPeriod, 'YTG');
# sLTD = name of the LTD consolidation for current period
sLTD = ATTRS(pDimension, pCurrentPeriod, 'LTD');
# Extract numeric FY year from attribute
# ── Extract FY year number and compute prior/next FY names ──
# Extract the FY year number from 'FY2027' → 2027
nFY = StringToNumber(SUBST(sCurrentFY, 3, 4));
# Prior FY name (e.g. 'FY2026')
sPriorFY = 'FY' | NumberToString(nFY - 1);
# Next FY name (e.g. 'FY2028')
sNextFY  = 'FY' | NumberToString(nFY + 1);
# OBL element name (e.g. '2027 OBL')
sOBL = NumberToString(nFY) | ' OBL';

# ─────────────────────────────────────────────
# Compute Prior-Year consolidation names
# Uses same calendar-month / fiscal-period formula
# as the Build Dimension TI
# ─────────────────────────────────────────────
nCalMonth = ATTRN(pDimension, pCurrentPeriod, 'Calendar Month');
nPriorFis = MOD(nCalMonth - pFYStartMonth + 12, 12) + 1;
sPriorYTD = 'YTD FY' | NumberToString(nFY - 1) | ' P' | IF(nPriorFis < 10, '0' | NumberToString(nPriorFis), NumberToString(nPriorFis));
sPriorYTG = 'YTG FY' | NumberToString(nFY - 1) | ' P' | IF(nPriorFis < 10, '0' | NumberToString(nPriorFis), NumberToString(nPriorFis));
sPriorLTD = 'LTD FY' | NumberToString(nFY - 1) | ' P' | IF(nPriorFis < 10, '0' | NumberToString(nPriorFis), NumberToString(nPriorFis));

# ══════ Subset: All Periods ══════
IF(SubsetExists(pDimension, 'All Periods') = 1);
  SubsetDestroy(pDimension, 'All Periods');
ENDIF;
SubsetCreate(pDimension, 'All Periods');
nPos = 1;
# Walk entire dimension, include leaf elements (exclude OBL)
vIdx = 1;
WHILE(vIdx <= vCount);
  sEl = DIMNM(pDimension, vIdx);
  IF(ElementLevel(pDimension, pDimension, sEl) = 0);
    IF(ATTRS(pDimension, sEl, 'Period Type') @<> 'OBL');
      SubsetElementInsert(pDimension, 'All Periods', sEl, nPos);
      nPos = nPos + 1;
    ENDIF;
  ENDIF;
  vIdx = vIdx + 1;
END;

# ══════ Subset: All FY ══════
IF(SubsetExists(pDimension, 'All FY') = 1);
  SubsetDestroy(pDimension, 'All FY');
ENDIF;
SubsetCreate(pDimension, 'All FY');
nPos = 1;
# Walk dimension, include only FY consolidations (names starting with 'FY')
vIdx = 1;
WHILE(vIdx <= vCount);
  sEl = DIMNM(pDimension, vIdx);
  IF(ElementLevel(pDimension, pDimension, sEl) > 0);
    IF(SUBST(sEl, 1, 2) @= 'FY');
      SubsetElementInsert(pDimension, 'All FY', sEl, nPos);
      nPos = nPos + 1;
    ENDIF;
  ENDIF;
  vIdx = vIdx + 1;
END;

# ══════ Subset: Current Period ══════
IF(SubsetExists(pDimension, 'Current Period') = 1);
  SubsetDestroy(pDimension, 'Current Period');
ENDIF;
SubsetCreate(pDimension, 'Current Period');
nPos = 1;
# Single element: the current period
IF(DIMIX(pDimension, pCurrentPeriod) > 0);
  SubsetElementInsert(pDimension, 'Current Period', pCurrentPeriod, nPos);
  nPos = nPos + 1;
ENDIF;

# ══════ Subset: Current FY ══════
IF(SubsetExists(pDimension, 'Current FY') = 1);
  SubsetDestroy(pDimension, 'Current FY');
ENDIF;
SubsetCreate(pDimension, 'Current FY');
nPos = 1;
# FY consolidation + all 12 months
IF(DIMIX(pDimension, sCurrentFY) > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'Current FY', sCurrentFY, nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, sCurrentFY);
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, sCurrentFY, nChild);
    SubsetElementInsert(pDimension, 'Current FY', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: Prior FY ══════
IF(SubsetExists(pDimension, 'Prior FY') = 1);
  SubsetDestroy(pDimension, 'Prior FY');
ENDIF;
SubsetCreate(pDimension, 'Prior FY');
nPos = 1;
# Prior FY consolidation + all 12 months
IF(DIMIX(pDimension, sPriorFY) > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'Prior FY', sPriorFY, nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, sPriorFY);
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, sPriorFY, nChild);
    SubsetElementInsert(pDimension, 'Prior FY', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: YTD ══════
IF(SubsetExists(pDimension, 'YTD') = 1);
  SubsetDestroy(pDimension, 'YTD');
ENDIF;
SubsetCreate(pDimension, 'YTD');
nPos = 1;
# YTD consolidation + its children (months Apr through current)
IF(DIMIX(pDimension, sYTD) > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'YTD', sYTD, nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, sYTD);
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, sYTD, nChild);
    SubsetElementInsert(pDimension, 'YTD', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: YTG ══════
IF(SubsetExists(pDimension, 'YTG') = 1);
  SubsetDestroy(pDimension, 'YTG');
ENDIF;
SubsetCreate(pDimension, 'YTG');
nPos = 1;
# YTG consolidation + its children (remaining months in FY)
IF(DIMIX(pDimension, sYTG) > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'YTG', sYTG, nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, sYTG);
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, sYTG, nChild);
    SubsetElementInsert(pDimension, 'YTG', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: LTD ══════
IF(SubsetExists(pDimension, 'LTD') = 1);
  SubsetDestroy(pDimension, 'LTD');
ENDIF;
SubsetCreate(pDimension, 'LTD');
nPos = 1;
# LTD = OBL + YTD consolidation + all month children (grandchildren)
IF(DIMIX(pDimension, sLTD) > 0);
  # Add LTD parent
  SubsetElementInsert(pDimension, 'LTD', sLTD, nPos);
  nPos = nPos + 1;
  # Add direct children of LTD (OBL + YTD)
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, sLTD);
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, sLTD, nChild);
    SubsetElementInsert(pDimension, 'LTD', sChild, nPos);
    nPos = nPos + 1;
    # For YTD child, also add its children (grandchildren = months)
    IF(sChild @<> sOBL);
      nGrand = 1;
      nGrandCount = ELCOMPN(pDimension, sChild);
      WHILE(nGrand <= nGrandCount);
        sGrand = ELCOMP(pDimension, sChild, nGrand);
        SubsetElementInsert(pDimension, 'LTD', sGrand, nPos);
        nPos = nPos + 1;
        nGrand = nGrand + 1;
      END;
    ENDIF;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: Prior Period ══════
IF(SubsetExists(pDimension, 'Prior Period') = 1);
  SubsetDestroy(pDimension, 'Prior Period');
ENDIF;
SubsetCreate(pDimension, 'Prior Period');
nPos = 1;
# Single element: the period before current
IF(DIMIX(pDimension, sPriorPeriod) > 0);
  SubsetElementInsert(pDimension, 'Prior Period', sPriorPeriod, nPos);
  nPos = nPos + 1;
ENDIF;

# ══════ Subset: Next FY ══════
IF(SubsetExists(pDimension, 'Next FY') = 1);
  SubsetDestroy(pDimension, 'Next FY');
ENDIF;
SubsetCreate(pDimension, 'Next FY');
nPos = 1;
# Next FY consolidation + all 12 months
IF(DIMIX(pDimension, sNextFY) > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'Next FY', sNextFY, nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, sNextFY);
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, sNextFY, nChild);
    SubsetElementInsert(pDimension, 'Next FY', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: Prior YTD ══════
IF(SubsetExists(pDimension, 'Prior YTD') = 1);
  SubsetDestroy(pDimension, 'Prior YTD');
ENDIF;
SubsetCreate(pDimension, 'Prior YTD');
nPos = 1;
IF(DIMIX(pDimension, sPriorYTD) > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'Prior YTD', sPriorYTD, nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, sPriorYTD);
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, sPriorYTD, nChild);
    SubsetElementInsert(pDimension, 'Prior YTD', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: Prior YTG ══════
IF(SubsetExists(pDimension, 'Prior YTG') = 1);
  SubsetDestroy(pDimension, 'Prior YTG');
ENDIF;
SubsetCreate(pDimension, 'Prior YTG');
nPos = 1;
IF(DIMIX(pDimension, sPriorYTG) > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'Prior YTG', sPriorYTG, nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, sPriorYTG);
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, sPriorYTG, nChild);
    SubsetElementInsert(pDimension, 'Prior YTG', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: Prior LTD ══════
IF(SubsetExists(pDimension, 'Prior LTD') = 1);
  SubsetDestroy(pDimension, 'Prior LTD');
ENDIF;
SubsetCreate(pDimension, 'Prior LTD');
nPos = 1;
# Prior LTD: same structure as LTD but for prior FY
sPriorOBL = NumberToString(nFY - 1) | ' OBL';
IF(DIMIX(pDimension, sPriorLTD) > 0);
  SubsetElementInsert(pDimension, 'Prior LTD', sPriorLTD, nPos);
  nPos = nPos + 1;
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, sPriorLTD);
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, sPriorLTD, nChild);
    SubsetElementInsert(pDimension, 'Prior LTD', sChild, nPos);
    nPos = nPos + 1;
    IF(sChild @<> sPriorOBL);
      nGrand = 1;
      nGrandCount = ELCOMPN(pDimension, sChild);
      WHILE(nGrand <= nGrandCount);
        sGrand = ELCOMP(pDimension, sChild, nGrand);
        SubsetElementInsert(pDimension, 'Prior LTD', sGrand, nPos);
        nPos = nPos + 1;
        nGrand = nGrand + 1;
      END;
    ENDIF;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: Rolling 12 ══════
IF(SubsetExists(pDimension, 'Rolling 12') = 1);
  SubsetDestroy(pDimension, 'Rolling 12');
ENDIF;
SubsetCreate(pDimension, 'Rolling 12');
nPos = 1;
# Rolling 12 subset: children of the 'Rolling 12' consolidation (built by dimension)
IF(DIMIX(pDimension, 'Rolling 12') > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'Rolling 12', 'Rolling 12', nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, 'Rolling 12');
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, 'Rolling 12', nChild);
    SubsetElementInsert(pDimension, 'Rolling 12', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: Rolling 6 ══════
IF(SubsetExists(pDimension, 'Rolling 6') = 1);
  SubsetDestroy(pDimension, 'Rolling 6');
ENDIF;
SubsetCreate(pDimension, 'Rolling 6');
nPos = 1;
# Rolling 6 subset: children of the 'Rolling 6' consolidation
IF(DIMIX(pDimension, 'Rolling 6') > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'Rolling 6', 'Rolling 6', nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, 'Rolling 6');
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, 'Rolling 6', nChild);
    SubsetElementInsert(pDimension, 'Rolling 6', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;

# ══════ Subset: Rolling 3 ══════
IF(SubsetExists(pDimension, 'Rolling 3') = 1);
  SubsetDestroy(pDimension, 'Rolling 3');
ENDIF;
SubsetCreate(pDimension, 'Rolling 3');
nPos = 1;
# Rolling 3 subset: children of the 'Rolling 3' consolidation
IF(DIMIX(pDimension, 'Rolling 3') > 0);
  # Add parent consolidation itself
  SubsetElementInsert(pDimension, 'Rolling 3', 'Rolling 3', nPos);
  nPos = nPos + 1;
  # Add all child elements
  nChild = 1;
  nChildCount = ELCOMPN(pDimension, 'Rolling 3');
  WHILE(nChild <= nChildCount);
    sChild = ELCOMP(pDimension, 'Rolling 3', nChild);
    SubsetElementInsert(pDimension, 'Rolling 3', sChild, nPos);
    nPos = nPos + 1;
    nChild = nChild + 1;
  END;
ENDIF;
